interface QuoteItem {
  type: string;
  damage: number;
}

const PROCESSING_FEE = 5;
const SWORD_BASE_PREMIUM = 100;

export function createQuote(items: unknown[]): number {
  const quoteItems = items as QuoteItem[];
  if (quoteItems.length === 0) {
    return PROCESSING_FEE;
  }
  // Single sword: base premium + processing fee
  if (quoteItems[0].type === "sword") {
    return SWORD_BASE_PREMIUM + PROCESSING_FEE;
  }
  return undefined as unknown as number;
}
